#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin>>n;
    int a[n],b[n];
    for(int i=0;i<n;i++){
        cin>>a[i];
    }
    for(int i=0;i<n;i++){
        cin>>b[i];
    }
    sort(a,a+n);
    int s=0;
    for(int i=0;i<n;i++){
        for(int j=0;j<n;j++){
            if(a[j]>b[i]){
                a[j]=-1;
                s++;
                break;
            }
        }
    }
    cout<<s;
    return 0;
}
